    73→ * Marker file for project root detection
    74→ *
    75→ * When this file exists in a directory, that directory is treated
    76→ * as a project root regardless of location.
    77→ */
    78→const PAI_ROOT_MARKER = '.pai-root';
    79→
    80→/**
    81→ * Project index directory
    82→ */
    83→const PROJECT_INDEX_DIR = paiPath('MEMORY', 'STATE', '.project-index');
    84→
    85→/**
    86→ * Project index file
    87→ */
    88→const PROJECT_INDEX_FILE = join(PROJECT_INDEX_DIR, 'projects.json');
