   251→        };
   252→      } else if (localMemory && index.projects[projectName]) {
   253→        index.projects[projectName].memoryPath = localMemory;
   254→      }
   255→    }
   256→  }
   257→
   258→  return index;
   259→}
   260→
   261→/**
   262→ * Parse META.yaml file for project metadata
   263→ */
   264→function parseMetaFile(metaPath: string): { project?: string; projectPath?: string; date?: string } {
   265→  try {
   266→    const content = fs.readFileSync(metaPath, "utf-8");
   267→    const lines = content.split("\n");
   268→
   269→    const result: Record<string, string> = {};
   270→    for (const line of lines) {
   271→      const match = line.match(/^(\w+):\s*(.+)$/);
   272→      if (match) {
   273→        result[match[1]] = match[2];
   274→      }
   275→    }
   276→
   277→    return {
   278→      project: result.project,
   279→      projectPath: result.project_path || result.projectPath,
   280→      date: result.date || result.created,
   281→    };
   282→  } catch {
   283→    return {};
   284→  }
   285→}
   286→
   287→// ============================================================================
   288→// Memory Scanning
   289→// ============================================================================
   290→
   291→/**
   292→ * Scan for memory files in a directory
   293→ */
   294→function scanMemories(baseDir: string, projectName: string, projectPath: string): MemoryFile[] {
   295→  const memories: MemoryFile[] = [];
   296→
   297→  if (!fs.existsSync(baseDir)) {
   298→    return memories;
   299→  }
   300→
   301→  // Scan WORK directory
   302→  const workDir = path.join(baseDir, "WORK");
   303→  if (fs.existsSync(workDir)) {
   304→    const workDirs = fs.readdirSync(workDir, { withFileTypes: true })
   305→      .filter(d => d.isDirectory())
   306→      .map(d => d.name)
   307→      .sort()
   308→      .reverse();
   309→
   310→    for (const workId of workDirs) {
   311→      const metaPath = path.join(workDir, workId, "META.yaml");
   312→      let description = workId;
   313→
   314→      if (fs.existsSync(metaPath)) {
   315→        const meta = parseMetaFile(metaPath);
   316→        description = meta.project || workId;
   317→      }
   318→
   319→      memories.push({
   320→        type: "WORK",
   321→        path: path.join(workDir, workId),
   322→        date: workId.split("-").slice(0, 3).join("-"), // Extract YYYY-MM-DD
   323→        description,
   324→        project: projectName,
   325→      });
   326→    }
   327→  }
   328→
   329→  // Scan LEARNING directory
   330→  const learningDir = path.join(baseDir, "LEARNING");
   331→  if (fs.existsSync(learningDir)) {
   332→    scanDirectoryRecursive(learningDir, memories, "LEARNING", projectName);
   333→  }
   334→
   335→  // Scan RESEARCH directory
   336→  const researchDir = path.join(baseDir, "RESEARCH");
   337→  if (fs.existsSync(researchDir)) {
   338→    scanDirectoryRecursive(researchDir, memories, "RESEARCH", projectName);
   339→  }
   340→
   341→  return memories;
   342→}
   343→
   344→/**
   345→ * Recursively scan directory for memory files
   346→ */
   347→function scanDirectoryRecursive(
   348→  dir: string,
   349→  memories: MemoryFile[],
   350→  type: "LEARNING" | "RESEARCH",
   351→  projectName: string
   352→): void {
   353→  const entries = fs.readdirSync(dir, { withFileTypes: true });
   354→
   355→  for (const entry of entries) {
   356→    const fullPath = path.join(dir, entry.name);
   357→
   358→    if (entry.isDirectory()) {
   359→      scanDirectoryRecursive(fullPath, memories, type, projectName);
   360→    } else if (entry.isFile() && entry.name.endsWith(".md")) {
   361→      const stats = fs.statSync(fullPath);
   362→      const date = new Date(stats.mtime).toISOString().split("T")[0];
   363→
   364→      // Extract description from filename
   365→      const description = entry.name
   366→        .replace(/\.md$/, "")
   367→        .replace(/^\d{8}_T?\d*_/, "") // Remove timestamp prefix
   368→        .replace(/_/g, " ")
   369→        .replace(/-/g, " ");
   370→
   371→      memories.push({
   372→        type,
   373→        path: fullPath,
   374→        date,
   375→        description,
   376→        project: projectName,
   377→      });
   378→    }
   379→  }
   380→}
   381→
   382→/**
   383→ * Get memories for a specific project
   384→ */
   385→function getProjectMemories(projectName: string): MemoryQueryResult | null {
   386→  const index = loadProjectIndex();
   387→  const project = index.projects[projectName];
   388→
   389→  if (!project) {
   390→    return null;
   391→  }
   392→
   393→  // Check for local memory first
   394→  let memories: MemoryFile[] = [];
   395→
   396→  if (project.memoryPath && fs.existsSync(project.memoryPath)) {
   397→    memories = scanMemories(project.memoryPath, projectName, project.path);
   398→  }
   399→
   400→  // Also check central memories for this project
   401→  const centralDir = path.join(MEMORY_DIR);
   402→  const centralMemories = scanMemories(centralDir, projectName, project.path);
   403→
   404→  // Merge and deduplicate
   405→  const seen = new Set<string>();
   406→  const allMemories = [...memories, ...centralMemories].filter(m => {
   407→    const key = `${m.type}:${m.path}`;
   408→    if (seen.has(key)) return false;
   409→    seen.add(key);
   410→    return true;
   411→  });
   412→
   413→  // Sort by date descending
   414→  allMemories.sort((a, b) => b.date.localeCompare(a.date));
   415→
   416→  // Count by type
   417→  const totalByType: Record<string, number> = {};
   418→  for (const memory of allMemories) {
   419→    totalByType[memory.type] = (totalByType[memory.type] || 0) + 1;
   420→  }
   421→
   422→  return {
   423→    project: projectName,
   424→    projectPath: project.path,
   425→    memories: allMemories,
   426→    totalByType,
   427→  };
   428→}
   429→
   430→/**
   431→ * Get memories for current project (detected from CWD)
   432→ */
   433→function getCurrentProjectMemories(): MemoryQueryResult | null {
   434→  const detected = detectProject();
   435→
   436→  if (!detected) {
   437→    return null;
   438→  }
   439→
   440→  return getProjectMemories(detected.name);
   441→}
   442→
   443→/**
   444→ * List all projects with memories
   445→ */
   446→function listAllProjects(): Array<ProjectInfo & { memoryCount: number }> {
   447→  const index = loadProjectIndex();
   448→  const projects: Array<ProjectInfo & { memoryCount: number }> = [];
   449→
   450→  for (const [name, project] of Object.entries(index.projects)) {
   451→    // Count actual memory files
   452→    const result = getProjectMemories(name);
   453→    const memoryCount = result ? result.memories.length : 0;
   454→
   455→    projects.push({
   456→      ...project,
   457→      name,
   458→      memoryCount,
   459→    });
   460→  }
   461→
   462→  // Sort by last active
   463→  projects.sort((a, b) => b.lastActive.localeCompare(a.lastActive));
   464→
   465→  return projects;
   466→}
   467→
   468→/**
   469→ * Get unified view of all memories (central + project)
   470→ */
   471→function getUnifiedMemories(typeFilter?: string): MemoryFile[] {
   472→  const index = loadProjectIndex();
   473→  const allMemories: MemoryFile[] = [];
   474→
   475→  // Add central memories
   476→  const centralMemories = scanMemories(MEMORY_DIR, "central", CLAUDE_DIR);
   477→  allMemories.push(...centralMemories);
   478→
   479→  // Add project memories
   480→  for (const [name, project] of Object.entries(index.projects)) {
   481→    if (name === "central") continue;
   482→
   483→    if (project.memoryPath && fs.existsSync(project.memoryPath)) {
   484→      const memories = scanMemories(project.memoryPath, name, project.path);
   485→      allMemories.push(...memories);
   486→    }
   487→  }
   488→
   489→  // Filter by type if specified
   490→  const filtered = typeFilter
   491→    ? allMemories.filter(m => m.type === typeFilter)
   492→    : allMemories;
   493→
   494→  // Sort by date descending
   495→  return filtered.sort((a, b) => b.date.localeCompare(a.date));
   496→}
   497→
   498→// ============================================================================
   499→// Output Formatting
   500→// ============================================================================
   501→
   502→/**
   503→ * Format memory query result as markdown table
   504→ */
   505→function formatMarkdown(result: MemoryQueryResult): string {
   506→  const lines: string[] = [];
   507→
   508→  lines.push(`# Project Memories: ${result.project}`);
   509→  lines.push();
   510→  lines.push(`**Path:** \`${result.projectPath}\``);
   511→  lines.push(`**Total Memories:** ${result.memories.length}`);
   512→  lines.push();
   513→
   514→  // Summary by type
   515→  lines.push("## Summary by Type");
   516→  lines.push();
   517→  lines.push("| Type | Count |");
   518→  lines.push("|------|-------|");
   519→  for (const [type, count] of Object.entries(result.totalByType)) {
   520→    lines.push(`| ${type} | ${count} |`);
   521→  }
   522→  lines.push();
   523→
   524→  // Memories table
   525→  lines.push("## Memories");
   526→  lines.push();
   527→  lines.push("| Type | Date | Description | Path |");
   528→  lines.push("|------|------|-------------|------|");
   529→
   530→  for (const memory of result.memories) {
   531→    const relativePath = memory.path.replace(HOME_DIR, "~");
   532→    lines.push(`| ${memory.type} | ${memory.date} | ${memory.description || "-"} | \`${relativePath}\` |`);
   533→  }
   534→
   535→  return lines.join("\n");
   536→}
   537→
   538→/**
   539→ * Format project list as markdown table
   540→ */
   541→function formatProjectList(projects: Array<ProjectInfo & { memoryCount: number }>): string {
   542→  const lines: string[] = [];
   543→
   544→  lines.push("# All Projects with Memories");
   545→  lines.push();
   546→  lines.push(`**Total Projects:** ${projects.length}`);
   547→  lines.push();
   548→
   549→  lines.push("| Project | Path | Work Sessions | Last Active | Local Memory |");
   550→  lines.push("|---------|------|---------------|-------------|--------------|");
   551→
   552→  for (const project of projects) {
   553→    const relativePath = project.path.replace(HOME_DIR, "~");
   554→    const lastActive = project.lastActive.split("T")[0];
   555→    const hasLocal = project.memoryPath ? "Yes" : "No";
   556→
   557→    lines.push(`| ${project.name} | \`${relativePath}\` | ${project.workIds.length} | ${lastActive} | ${hasLocal} |`);
   558→  }
   559→
   560→  return lines.join("\n");
   561→}
   562→
   563→/**
   564→ * Format unified memories as markdown table
   565→ */
   566→function formatUnifiedMemories(memories: MemoryFile[]): string {
   567→  const lines: string[] = [];
   568→
   569→  lines.push("# Unified Memory Index");
   570→  lines.push();
   571→  lines.push(`**Total Memories:** ${memories.length}`);
   572→  lines.push();
   573→
   574→  lines.push("| Type | Project | Date | Description | Path |");
   575→  lines.push("|------|---------|------|-------------|------|");
   576→
   577→  for (const memory of memories) {
   578→    const relativePath = memory.path.replace(HOME_DIR, "~");
   579→    lines.push(`| ${memory.type} | ${memory.project} | ${memory.date} | ${memory.description || "-"} | \`${relativePath}\` |`);
   580→  }
   581→
   582→  return lines.join("\n");
   583→}
   584→
   585→/**
   586→ * Format as JSON
   587→ */
   588→function formatJson(data: unknown): string {
   589→  return JSON.stringify(data, null, 2);
   590→}
   591→
   592→// ============================================================================
   593→// CLI
   594→// ============================================================================
   595→
   596→const { values, positionals } = parseArgs({
   597→  args: Bun.argv.slice(2),
   598→  options: {
   599→    current: { type: "boolean" },
   600→    project: { type: "string" },
   601→    list: { type: "boolean" },
